"use strict";const t=t=>t instanceof Date?t:"number"==typeof t?new Date(t):"string"==typeof t?t.includes("T")?new Date(t):new Date(t.replace(/-/g,"/")):new Date,e=(e,n="yyyy-mm-dd hh:MM:ss")=>{const r=t(e),o={"y+":r.getFullYear().toString(),"m+":(r.getMonth()+1).toString(),"d+":r.getDate().toString(),"h+":r.getHours().toString(),"M+":r.getMinutes().toString(),"s+":r.getSeconds().toString()};let g;for(let t in o)g=new RegExp("("+t+")").exec(n),g&&(n=n.replace(g[1],1==g[1].length?o[t]:o[t].padStart(g[1].length,"0")));return n};exports.formatTimeAgo=n=>{const r=t(n),o=((new Date).getTime()-r.getTime())/1e3;if(o<60)return"刚刚";const g=Math.floor(o/60);if(g<60)return`${g}分钟前`;const i=Math.floor(g/60);if(i<24)return`${i}小时前`;const s=Math.floor(i/24);return 1===s?"昨天":s<7?`${s}天前`:e(r,"yyyy-mm-dd")};
